# After (fixed):
def build_order_query(status, start_date=None, end_date=None):
    start = start_date or "DATE_SUB(CURRENT_DATE(), INTERVAL 7 DAY)"
    end   = end_date   or "CURRENT_DATE()"
    return f"""
    SELECT ... FROM orders
    WHERE order_date BETWEEN {start} AND {end}
      AND status = '{status}'
    """.strip()
